export const RESTAURANTS = (() => {
  const seen = new Set();
  return RESTAURANTS_RAW.filter(r => {
    const key = `${r.name}||${r.city}||${r.neighborhood}`;
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  });
})();
